# ruff: noqa: E501
import base64


# This will decode invoice request
def decode_invoice(encoded_invoice):
    encoded_bytes = encoded_invoice.encode("utf-8")
    decoded_bytes = base64.b64decode(encoded_bytes)
    decoded_string = decoded_bytes.decode("utf-8")
    print("Decoded Invoice: START")
    print(decoded_string)
    print("Decoded Invoice: END")
    return decoded_string


# This will decode certificate, csid
def decode_csid(csid):
    encoded_bytes = csid.encode("utf-8")
    decoded_bytes = base64.b64decode(encoded_bytes)
    decoded_string = decoded_bytes.decode("utf-8")
    print("Decoded Certificate:")
    print(decoded_string)
    return decoded_string


def main():
    # Provide the input string directly

    # Decode CSID
    # decoded_csid = decode_csid(csid)

    # Decode Invoice
    invoice = ""  # noqa: E501

    # Decode without storing to avoid unused variable
    decode_invoice(invoice)


if __name__ == "__main__":
    main()
